import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Button,
  Grid,
  Card,
  CardContent,
  Divider,
  Avatar,
  Chip,
  IconButton,
  Menu,
  MenuItem,
  TextField,
  InputAdornment,
  Tabs,
  Tab,
  Skeleton,
  Paper
} from '@mui/material';
import { Link as RouterLink } from 'react-router-dom';
import AddIcon from '@mui/icons-material/Add';
import SearchIcon from '@mui/icons-material/Search';
import MoreVertIcon from '@mui/icons-material/MoreVert';
import VerifiedIcon from '@mui/icons-material/Verified';
import PendingIcon from '@mui/icons-material/Pending';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import { useTheme } from '@mui/material/styles';

const DashboardPage = () => {
  const theme = useTheme();
  const [testimonials, setTestimonials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tabValue, setTabValue] = useState(0);
  const [anchorEl, setAnchorEl] = useState(null);
  const [selectedTestimonial, setSelectedTestimonial] = useState(null);

  // Simulate fetching testimonials
  useEffect(() => {
    setTimeout(() => {
      setTestimonials([
        {
          id: '1',
          clientName: 'Michael Thompson',
          clientCompany: 'Acme Inc.',
          original: 'The coaching was good. I learned some things that helped me.',
          enhanced: 'Working with this coach transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. The coaching didnt just teach me tactics—it changed my entire mindset about whats possible.',
          status: 'verified',
          date: '2023-05-15',
          industry: 'Coaching'
        },
        {
          id: '2',
          clientName: 'Jessica Kim',
          clientCompany: 'Design Studio',
          original: 'They built a nice website for me. It works well.',
          enhanced: 'The team at DesignPro delivered beyond my expectations. My new website has increased conversions by 43% in the first month alone. Their attention to detail and strategic approach to UX completely transformed my online presence.',
          status: 'pending',
          date: '2023-05-10',
          industry: 'Web Design'
        },
        {
          id: '3',
          clientName: 'David Rodriguez',
          clientCompany: 'Fitness First',
          original: 'Good trainer. I lost some weight and feel better.',
          enhanced: 'After 3 months with Alex, Ive lost 28 pounds and completely transformed my relationship with fitness. His personalized approach addressed my specific challenges, and for the first time in my life, I actually look forward to my workouts!',
          status: 'verified',
          date: '2023-05-05',
          industry: 'Fitness'
        }
      ]);
      setLoading(false);
    }, 1500);
  }, []);

  const handleTabChange = (event, newValue) => {
    setTabValue(newValue);
  };

  const handleMenuClick = (event, testimonial) => {
    setAnchorEl(event.currentTarget);
    setSelectedTestimonial(testimonial);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const filteredTestimonials = testimonials.filter(testimonial => {
    if (tabValue === 0) return true;
    if (tabValue === 1) return testimonial.status === 'verified';
    if (tabValue === 2) return testimonial.status === 'pending';
    return true;
  });

  return (
    <Box sx={{ py: 6 }}>
      <Container maxWidth="lg">
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
          <Typography variant="h3">Your Testimonials</Typography>
          <Button 
            variant="contained" 
            color="primary"
            startIcon={<AddIcon />}
            component={RouterLink}
            to="/enhance"
          >
            New Testimonial
          </Button>
        </Box>

        <Box sx={{ mb: 4 }}>
          <Grid container spacing={3}>
            <Grid item xs={12} md={8}>
              <TextField
                fullWidth
                placeholder="Search testimonials..."
                variant="outlined"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <SearchIcon color="action" />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'white'
                  }
                }}
              />
            </Grid>
            <Grid item xs={12} md={4}>
              <Box sx={{ display: 'flex', gap: 2 }}>
                <TextField
                  select
                  fullWidth
                  defaultValue="all"
                  variant="outlined"
                  label="Industry"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      backgroundColor: 'white'
                    }
                  }}
                >
                  <MenuItem value="all">All Industries</MenuItem>
                  <MenuItem value="coaching">Coaching</MenuItem>
                  <MenuItem value="webdesign">Web Design</MenuItem>
                  <MenuItem value="fitness">Fitness</MenuItem>
                </TextField>
              </Box>
            </Grid>
          </Grid>
        </Box>

        <Box sx={{ mb: 4, borderBottom: 1, borderColor: 'divider' }}>
          <Tabs 
            value={tabValue} 
            onChange={handleTabChange}
            sx={{
              '& .MuiTab-root': {
                textTransform: 'none',
                fontWeight: 600,
                fontSize: '0.9rem',
                minWidth: 100
              }
            }}
          >
            <Tab label="All" />
            <Tab label="Verified" />
            <Tab label="Pending" />
          </Tabs>
        </Box>

        {loading ? (
          <Grid container spacing={3}>
            {[1, 2, 3].map((item) => (
              <Grid item xs={12} key={item}>
                <Card sx={{ borderRadius: 3 }}>
                  <CardContent sx={{ p: 3 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                      <Skeleton variant="circular" width={40} height={40} sx={{ mr: 2 }} />
                      <Box>
                        <Skeleton variant="text" width={120} />
                        <Skeleton variant="text" width={80} />
                      </Box>
                    </Box>
                    <Skeleton variant="rectangular" height={100} sx={{ borderRadius: 1, mb: 2 }} />
                    <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                      <Skeleton variant="text" width={100} />
                      <Skeleton variant="text" width={80} />
                    </Box>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        ) : (
          <>
            {filteredTestimonials.length === 0 ? (
              <Box sx={{ textAlign: 'center', py: 8 }}>
                <Typography variant="h5" gutterBottom>No testimonials found</Typography>
                <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
                  {tabValue === 0 ? "You haven't created any testimonials yet." : 
                   tabValue === 1 ? "You don't have any verified testimonials yet." :
                   "You don't have any pending testimonials."}
                </Typography>
                {tabValue === 0 && (
                  <Button 
                    variant="contained" 
                    color="primary"
                    startIcon={<AddIcon />}
                    component={RouterLink}
                    to="/enhance"
                  >
                    Create Your First Testimonial
                  </Button>
                )}
              </Box>
            ) : (
              <Grid container spacing={3}>
                {filteredTestimonials.map((testimonial) => (
                  <Grid item xs={12} key={testimonial.id}>
                    <Card 
                      sx={{ 
                        borderRadius: 3,
                        transition: 'transform 0.2s ease-in-out, box-shadow 0.2s ease-in-out',
                        '&:hover': {
                          transform: 'translateY(-4px)',
                          boxShadow: theme.shadows[3]
                        }
                      }}
                    >
                      <CardContent sx={{ p: 3 }}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 2 }}>
                          <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            <Avatar 
                              sx={{ 
                                bgcolor: testimonial.status === 'verified' ? 'success.light' : 'info.light',
                                color: testimonial.status === 'verified' ? 'success.dark' : 'info.dark',
                                mr: 2
                              }}
                            >
                              {testimonial.clientName.charAt(0)}
                            </Avatar>
                            <Box>
                              <Typography variant="h6">{testimonial.clientName}</Typography>
                              <Typography variant="body2" color="text.secondary">
                                {testimonial.clientCompany}
                              </Typography>
                            </Box>
                          </Box>

                          <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            <Chip 
                              icon={testimonial.status === 'verified' ? <VerifiedIcon /> : <PendingIcon />}
                              label={testimonial.status === 'verified' ? 'Verified' : 'Pending'}
                              color={testimonial.status === 'verified' ? 'success' : 'info'}
                              size="small"
                              sx={{ mr: 1 }}
                            />
                            <IconButton
                              aria-label="more"
                              onClick={(e) => handleMenuClick(e, testimonial)}
                            >
                              <MoreVertIcon />
                            </IconButton>
                          </Box>
                        </Box>

                        <Paper 
                          elevation={0} 
                          sx={{ 
                            p: 2, 
                            mb: 2, 
                            bgcolor: 'grey.50',
                            borderRadius: 2
                          }}
                        >
                          <Typography variant="body2" color="text.secondary" gutterBottom>
                            Original:
                          </Typography>
                          <Typography variant="body2">
                            {testimonial.original}
                          </Typography>
                        </Paper>

                        <Paper 
                          elevation={0} 
                          sx={{ 
                            p: 2, 
                            mb: 2, 
                            bgcolor: 'primary.light',
                            borderRadius: 2
                          }}
                        >
                          <Typography variant="body2" color="primary.dark" gutterBottom>
                            Enhanced:
                          </Typography>
                          <Typography variant="body2" color="primary.dark" sx={{ fontWeight: 500 }}>
                            {testimonial.enhanced}
                          </Typography>
                        </Paper>

                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <Box sx={{ display: 'flex', gap: 1 }}>
                            <Chip 
                              label={testimonial.industry} 
                              size="small" 
                              sx={{ bgcolor: 'grey.100' }}
                            />
                            <Chip 
                              label={new Date(testimonial.date).toLocaleDateString()} 
                              size="small"
                              sx={{ bgcolor: 'grey.100' }}
                            />
                          </Box>

                          <Button
                            startIcon={<ContentCopyIcon />}
                            size="small"
                          >
                            Copy
                          </Button>
                        </Box>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            )}
          </>
        )}

        <Menu
          anchorEl={anchorEl}
          open={Boolean(anchorEl)}
          onClose={handleMenuClose}
        >
          <MenuItem onClick={handleMenuClose}>Edit</MenuItem>
          <MenuItem onClick={handleMenuClose}>Share</MenuItem>
          <MenuItem onClick={handleMenuClose}>Download</MenuItem>
          <Divider />
          <MenuItem onClick={handleMenuClose} sx={{ color: 'error.main' }}>Delete</MenuItem>
        </Menu>
      </Container>
    </Box>
  );
};

export default DashboardPage;
